// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract PackedData {
    uint256 private packed;

    function a() external view returns (uint80) {
        return [[SLOT field_a]];
    }

    function b() external view returns (uint80) {
        return [[SLOT field_b]];
    }

    function c() external view returns (uint80) {
        return [[SLOT field_c]];
    }

    function setAll(uint80 _a, uint80 _b, uint80 _c) external {
        packed = [[SLOT pack_all]];
    }

    function getAll() external view returns (uint80, uint80, uint80) {
        uint256 p = packed;
        return (uint80(p), uint80(p >> 80), uint80(p >> 160));
    }

    function incrementA() external {
        uint256 p = packed;
        unchecked {
            uint80 newA = uint80(p) + 1;
            packed = (p & ~uint256(type(uint80).max)) | uint256(newA);
        }
    }

    function incrementB() external {
        uint256 p = packed;
        unchecked {
            uint80 newB = uint80(p >> 80) + 1;
            packed = (p & ~(uint256(type(uint80).max) << 80)) | (uint256(newB) << 80);
        }
    }

    function incrementC() external {
        uint256 p = packed;
        unchecked {
            uint80 newC = uint80(p >> 160) + 1;
            packed = (p & ~(uint256(type(uint80).max) << 160)) | (uint256(newC) << 160);
        }
    }
}
